1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const ALIKE_BLOCK_SIZE = 3;
10	const ALIKE_BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
35	type Damage = { itemType: string; amount: number };
36	type Incident = { cause: string; damages: Damage[] };
37	type QuoteStep = { op: "quote"; items: Item[] };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	type Step = QuoteStep | ClaimStep;
40	type Customer = { yearsWithMHPCO: number };
41	type Scenario = { customer: Customer; steps: Step[] };
42	type Policy = { items: Item[]; cap: number };
43	
44	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
45	
46	const groupByType = (items: Item[]): Item[][] => {
47	  const groups = Map.groupBy(items, (item) => item.type);
48	  return Array.from(groups.values());
49	};
50	
51	const sumBasePremiums = (items: Item[]): number =>
52	  items.reduce((acc, item) => acc + basePremiumOf(item), 0);
53	
54	const basePremiumForGroup = (group: Item[]): number =>
55	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
56	
57	const basePremiumForItems = (items: Item[]): number =>
58	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
59	
60	const cursedSurcharge = (item: Item): number =>
61	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
62	
63	const highEnchantmentSurcharge = (item: Item): number =>
64	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
65	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
66	    : 0;
67	
68	const itemSurcharges = (items: Item[]): number =>
69	  items.reduce(
70	    (sum, item) => sum + cursedSurcharge(item) + highEnchantmentSurcharge(item),
71	    0,
72	  );
73	
74	const firstInsuranceSurcharge = (basePremium: number): number =>
75	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
76	
77	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
78	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
79	
80	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
81	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
82	
83	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
84	  const basePremium = basePremiumForItems(items);
85	  return (
86	    Math.ceil(
87	      basePremium +
88	        itemSurcharges(items) +
89	        firstInsuranceSurcharge(basePremium) -
90	        loyaltyDiscount(basePremium, customer) -
91	        followUpDiscount(basePremium, isFollowUp),
92	    ) + PROCESSING_FEE
93	  );
94	};
95	
96	const insuranceSum = (items: Item[]): number =>
97	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
98	
99	const reimbursableAmount = (item: Item, damageAmount: number): number =>
100	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
101	    ? damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE
102	    : damageAmount;
103	
104	const payoutForDamage = (item: Item, damage: Damage): number =>
105	  reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
106	
107	const openPolicy = (items: Item[]): Policy => ({
108	  items,
109	  cap: insuranceSum(items) * CAP_MULTIPLIER,
110	});
111	
112	const findItem = (policy: Policy, itemType: string): Item =>
113	  policy.items.find((i) => i.type === itemType) as Item;
114	
115	const settleClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
116	  const payoutFor = (damage: Damage) => payoutForDamage(findItem(policy, damage.itemType), damage);
117	  const desiredPayout = incident.damages.reduce((sum, damage) => sum + payoutFor(damage), 0);
118	  const payout = Math.floor(Math.min(desiredPayout, policy.cap));
119	  return { payout, remainingCap: policy.cap - payout };
120	};
121	
122	const quoteResult = (step: QuoteStep, customer: Customer, isFollowUp: boolean) => ({
123	  premium: quotePremium(step.items, customer, isFollowUp),
124	});
125	
126	export const runScenario = (scenario: Scenario): unknown => {
127	  const policies: Policy[] = [];
128	  const results = scenario.steps.map((step) => {
129	    if (step.op === "claim") {
130	      const policy = policies[step.policy];
131	      const result = settleClaim(policy, step.incident);
132	      policies[step.policy] = { ...policy, cap: result.remainingCap };
133	      return result;
134	    }
135	    const isFollowUp = policies.length > 0;
136	    policies.push(openPolicy(step.items));
137	    return quoteResult(step, scenario.customer, isFollowUp);
138	  });
139	  return { results };
140	};
